const items = $input.all();

const highImpactKeywords = [
  'gpt', 'gemini', 'claude', 'llm', 'artificial intelligence',
  'openai', 'anthropic', 'google deepmind', 'meta ai', 'mistral',
  'model', 'breakthrough', 'release', 'launch', 'regulation',
  'agi', 'agent', 'multimodal', 'reasoning', 'benchmark',
  'inteligencia artificial', 'inteligencia', 'ia ', ' ai ',
  'modelo', 'lanzamiento', 'regulacion', 'regulación', 'agente',
  'aprendizaje', 'machine learning', 'deep learning', 'chatgpt',
  'copilot', 'nvidia', 'sam altman', 'demis hassabis'
];

const excludeKeywords = [
  'how to use', 'tutorial basico', 'tips', 'tricks', 'quiz',
  'deal', 'sale', 'discount', 'coupon', 'oferta', 'precio',
  'comprar', 'chollos'
];

const seen = new Set();
const filtered = items
  .filter(item => {
    const title = (item.json.title || '').toLowerCase();
    const text = (title + ' ' + (item.json.contentSnippet || '') + ' ' + (item.json.categories || []).join(' ')).toLowerCase();
    const hasHighImpact = highImpactKeywords.some(kw => text.includes(kw));
    const hasExcluded = excludeKeywords.some(kw => text.includes(kw));
    const hasLink = !!(item.json.link || item.json.guid);
    const isDuplicate = seen.has(title.substring(0, 40));
    if (!isDuplicate) seen.add(title.substring(0, 40));
    return hasHighImpact && !hasExcluded && hasLink && !isDuplicate;
  })
  .slice(0, 8);

const tagMap = ['IA', 'Modelos', 'Investigación', 'Industria', 'Tecnología', 'Agentes', 'Regulación', 'Innovación'];

return filtered.map((item, i) => ({
  json: {
    title: item.json.title || 'Sin título',
    summary: item.json.contentSnippet
      ? item.json.contentSnippet.substring(0, 220) + '...'
      : item.json.content
        ? item.json.content.replace(/<[^>]*>/g, '').substring(0, 220) + '...'
        : 'Ver artículo completo.',
    link: item.json.link || item.json.guid || '#',
    source: (() => {
      try {
        const url = item.json.link || item.json.guid || '';
        return url ? new URL(url).hostname.replace('www.', '') : 'fuente';
      } catch(e) { return 'fuente'; }
    })(),
    date: item.json.pubDate
      ? new Date(item.json.pubDate).toLocaleDateString('es-ES', { day: 'numeric', month: 'short', year: 'numeric' })
      : new Date().toLocaleDateString('es-ES', { day: 'numeric', month: 'short', year: 'numeric' }),
    tag: tagMap[i % tagMap.length],
    isFeatured: i === 0
  }
}));

const articles = $input.all();

const today = new Date().toLocaleDateString('es-ES', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});
const todayCap = today.charAt(0).toUpperCase() + today.slice(1);

const emailHTML = `<!DOCTYPE html><html><head><meta charset="UTF-8"></head>
<body style="background:#09090f;margin:0;padding:32px 16px;font-family:system-ui,sans-serif">
<div style="max-width:520px;margin:0 auto">
  <div style="margin-bottom:28px">
    <span style="font-family:monospace;font-size:12px;color:#38bdf8;letter-spacing:0.2em">AI SIGNAL</span>
    <h1 style="color:#f0f0ff;font-size:26px;font-weight:700;margin:12px 0 8px;line-height:1.2">Lo que mueve la IA hoy</h1>
    <p style="color:rgba(240,240,255,0.5);font-size:13px;margin:0 0 4px">${todayCap}</p>
    <p style="color:rgba(240,240,255,0.3);font-size:11px;font-family:monospace">Fuentes: The Verge · TechCrunch · VentureBeat · Xataka · MIT Tech Review</p>
  </div>
  <div style="background:rgba(255,255,255,0.04);border:1px solid rgba(255,255,255,0.1);border-radius:16px;padding:28px;margin-bottom:24px">
    <p style="color:rgba(240,240,255,0.7);font-size:14px;line-height:1.7;margin:0 0 24px">
      Tu newsletter diario de IA está listo. <strong style="color:#f0f0ff">${articles.length} noticias de alto impacto</strong> seleccionadas hoy desde fuentes en inglés y español.
    </p>
  </div>
  ${articles.slice(0,3).map(item => {
    const a = item.json;
    return `<div style="border-left:2px solid rgba(167,139,250,0.4);padding:0 0 0 16px;margin-bottom:18px">
      <p style="color:#a78bfa;font-family:monospace;font-size:9px;letter-spacing:0.15em;text-transform:uppercase;margin:0 0 6px">${a.tag} · ${a.source}</p>
      <p style="color:#f0f0ff;font-size:14px;font-weight:600;margin:0 0 6px;line-height:1.4">${a.title}</p>
      <p style="color:rgba(240,240,255,0.5);font-size:12px;margin:0 0 8px;line-height:1.6">${a.summary.substring(0,140)}...</p>
      <a href="${a.link}" style="color:#38bdf8;font-size:11px;font-family:monospace">Leer artículo →</a>
    </div>`;
  }).join('')}
  <p style="color:rgba(240,240,255,0.25);font-size:11px;text-align:center;margin-top:32px">AI Signal · Automatizado con N8N</p>
</div>
</body></html>`;

return [{ json: {
  emailHTML,
  subject: `AI Signal — ${todayCap}`,
  articleCount: articles.length
}}];
